class Solution {
    public int flipLights(int n, int presses) {
        int[] dp = new int[presses + 1];
        dp[0] = 1;
        for (int i = 1; i <= presses; i++) {
            dp[i] = (dp[i - 1] * 4) % 1000000007;
        }
        return dp[presses];
    }
}
